295	char decide_tilt_direction_logic(const GameState& current_gs_after_placement) {
296	    double best_overall_eval = std::numeric_limits<double>::lowest();
297	    int best_dir_idx = 0;
298	
299	    int turn_T = current_gs_after_placement.turn_num_1_indexed;
