double evaluate_fast() const {
    if (num_candies == 0) return 0.0;

    int same_adj = 0;
    int diff_adj = 0;
    int near_miss = 0;

    for (int r = 0; r < GRID_SIZE; ++r) {
        for (int c = 0; c < GRID_SIZE; ++c) {
            if (board[r][c] == 0) continue;
            int f = board[r][c];
            if (c + 1 < GRID_SIZE) {
                if (board[r][c + 1] == f) same_adj++;
                else if (board[r][c + 1] != 0) diff_adj++;
            }
            if (r + 1 < GRID_SIZE) {
                if (board[r + 1][c] == f) same_adj++;
                else if (board[r + 1][c] != 0) diff_adj++;
            }
            // Near-miss: same flavor at distance 2 (gap of 1 cell)
            if (c + 2 < GRID_SIZE && board[r][c + 2] == f && board[r][c + 1] != f) near_miss++;
            if (r + 2 < GRID_SIZE && board[r + 2][c] == f && board[r + 1][c] != f) near_miss++;
        }
    }

    // Count same-flavor cells in same row/column (line connectivity potential)
    int line_bonus = 0;
    for (int r = 0; r < GRID_SIZE; ++r) {
        std::array<int, NUM_FLAVORS + 1> row_count{};
        for (int c = 0; c < GRID_SIZE; ++c) {
            if (board[r][c] != 0) row_count[board[r][c]]++;
        }
        for (int f = 1; f <= NUM_FLAVORS; ++f) {
            if (row_count[f] > 1) line_bonus += row_count[f] * row_count[f];
        }
    }
    for (int c = 0; c < GRID_SIZE; ++c) {
        std::array<int, NUM_FLAVORS + 1> col_count{};
        for (int r = 0; r < GRID_SIZE; ++r) {
            if (board[r][c] != 0) col_count[board[r][c]]++;
